/// <summary>
/// Controller class for - Elevator receipt report 
/// </summary>
class ETGElevatorReceiptReportController extends SrsReportRunController
{
}

Method.Source:
public static ETGElevatorReceiptReportController construct()
{
    return new ETGElevatorReceiptReportController();
}

public static void main(Args _args)
{
    ETGElevatorReceiptReportController controller = ETGElevatorReceiptReportController::construct();

    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGElevatorReceiptReport,Design));
    controller.parmDialogCaption("@ETG_New:ElevatorReceipt");
    controller.startOperation();
}

void prePromptModifyContract()
{        
    ETGElevatorReceiptTable             etgElevatorReceiptTable =  this.parmArgs().record();
    ETGElevatorReceiptReportContract    contract = this.parmReportContract().parmRdpContract();
    contract.parmElevatorReceiptNumber(etgElevatorReceiptTable.ElevatorReceiptNumber);
}
